-- 1. 删除这些账号的partner_cities记录
DELETE FROM partner_cities
WHERE partnerId IN (
  SELECT id FROM partners
  WHERE userId IN (16028537, 16028538, 16028539, 16028540, 16028541, 16028542, 16028543, 16028544)
);

-- 2. 删除这些账号的partners记录
DELETE FROM partners
WHERE userId IN (16028537, 16028538, 16028539, 16028540, 16028541, 16028542, 16028543, 16028544);

-- 3. 删除这些账号的users记录
DELETE FROM users
WHERE id IN (16028537, 16028538, 16028539, 16028540, 16028541, 16028542, 16028543, 16028544);

-- 4. 验证删除结果
SELECT '脏数据账号已清理' as result;

